tool_input.script:
export const meta = {
  name: 'qa-semantic-search',
  description: 'Semantic search for QA workflow',
  phases: [
    { title: 'Search', detail: 'Execute semantic search for relevant knowledge sections' }
  ]
}

phase('Search')

const result = await agent(`
Execute the semantic search workflow defined in workflows/semantic-search.md.

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

The query is:
"DBからデータを読み込んで集計し、結果を別テーブルに書き込む定期処理を作りたい。どういう構成で実装すればいい？（処理方式: Nablarchバッチ）（目的: 実装したい）"

Read the file at workflows/semantic-search.md in the working directory and execute the workflow exactly as specified.

Return a JSON object with:
{
  "selected_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "relevance": "<high|partial>"}
  ],
  "selected_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why skipped>"}
  ],
  "excluded_sections": [
    {"file": "<file path>", "section_id": "<sN>", "reason": "<why skipped>"}
  ]
}
`, {
  label: 'semantic-search',
  phase: 'Search',
  schema: {
    type: 'object',
    properties: {
      selected_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            file: { type: 'string' },
            section_id: { type: 'string' },
            relevance: { type: 'string', enum: ['high', 'partial'] }
          },
          required: ['file', 'section_id', 'relevance']
        }
      },
      selected_pages: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            path: { type: 'string' },
            reason: { type: 'string' }
          },
          required: ['path', 'reason']
        }
      },
      excluded_pages: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            path: { type: 'string' },
            reason: { type: 'string' }
          },
          required: ['path', 'reason']
        }
      },
      excluded_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            file: { type: 'string' },
            section_id: { type: 'string' },
            reason: { type: 'string' }
          },
          required: ['file', 'section_id', 'reason']
        }
      }
    },
    required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections']
  }
})

return result
